mapper.select:
SELECT c.*
FROM caregiver c
LEFT JOIN caregiver_stats s ON c.id = s.caregiver_id
WHERE c.city_code = #{cityCode}
  AND c.verify_status = 1

    AND c.gender = #{gender}


    AND c.real_name LIKE CONCAT('%', #{nameKeyword}, '%')


    AND c.birthday >= #{minBirthday}


    AND c.birthday <= #{maxBirthday}


    AND c.work_years >= #{minWorkYears}


    AND c.work_years <= #{maxWorkYears}


    AND c.education = #{education}


    AND EXISTS (
        SELECT 1
        FROM caregiver_service_config cfg
        JOIN service_package sp
          ON sp.id = cfg.package_id
         AND sp.status = 1
        WHERE cfg.caregiver_id = c.id
          AND sp.category = #{packageCategory}
    )

ORDER BY


        COALESCE(s.order_count, 0) ${sortOrder}, c.create_time DESC


        COALESCE(s.good_review_rate, 0) ${sortOrder}, c.create_time DESC


        c.work_years ${sortOrder}, c.create_time DESC


        c.create_time DESC
